const item = $input.item.json;
const subject = item.subject || '';
const rawBody = item.body?.content || item.bodyPreview || '';
const body = rawBody
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const parts = subject.split('-');
const candidate = parts[parts.length - 1].trim();
const keywords = ['錄取','通知','耕興','全球','股份','有限','RE:','re:'];
const name_from_subject = (
  candidate.length >= 2 && candidate.length <= 5 &&
  !keywords.some(k => candidate.includes(k))
) ? candidate : null;

return {
  email_msg_id: item.id,
  email_subject: subject,
  email_web_link: item.webLink || null,
  sender: item.from?.emailAddress?.address || null,
  received_at: item.receivedDateTime,
  source_type: 'onboarding',
  name_from_subject: name_from_subject,
  body_text: body.substring(0, 2000),
};

const base = $('Code：萃取 name_from_subject').item.json;
let aiResult = {};
try {
  const raw = $input.item.json.content;
  const text = Array.isArray(raw) ? (raw[0]?.text || '') : (typeof raw === 'string' ? raw : '');
  const match = text.match(/\{[\s\S]*\}/);
  if (match) aiResult = JSON.parse(match[0]);
} catch(e) {}

// Parse scheduled_onboard_date from body as fallback
let regexDate = null;
const bodyText = base.body_text || '';
const datePatterns = [
  { re: /報到日期[：:]\s*(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/, fn: m => m[1]+'-'+m[2].padStart(2,'0')+'-'+m[3].padStart(2,'0') },
  { re: /預定報到日期[：:]\s*(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/, fn: m => m[1]+'-'+m[2].padStart(2,'0')+'-'+m[3].padStart(2,'0') },
];
for (const {re, fn} of datePatterns) {
  const m = bodyText.match(re);
  if (m) { regexDate = fn(m); break; }
}

const normalizeText = value => String(value || '').replace(/\s+/g, '').replace(/[()??]/g, '').trim();
const hasAny = (text, keywords) => keywords.some(keyword => text.includes(keyword));
const canonicalizeDepartment = (rawDepartment, emailSubject) => {
  const departmentText = normalizeText(rawDepartment);
  const subjectText = normalizeText(emailSubject);
  const combined = `${departmentText} ${subjectText}`;
  if (hasAny(combined, ['??'])) return '??';
  if (hasAny(combined, ['??'])) return '??';
  if (hasAny(combined, ['??'])) return '??';
  if (hasAny(combined, ['ICC', '??'])) return '??';
  if (hasAny(combined, ['??'])) return '??';
  if (hasAny(combined, ['??', '??', '????', '???'])) return '??/??';
  return String(rawDepartment || '').trim() || null;
};
const canonicalizePosition = (rawPosition, department, rawDepartment, emailSubject) => {
  const positionText = normalizeText(rawPosition);
  const departmentText = normalizeText(rawDepartment || department);
  const subjectText = normalizeText(emailSubject);
  const combined = `${subjectText} ${positionText} ${departmentText}`;
  if (hasAny(combined, ['RFSAR', 'SAR???', 'SAR?????'])) return 'RF SAR ?????';
  if (departmentText.includes('SAR???') && hasAny(combined, ['???', '????'])) return 'RF SAR ?????';
  if (departmentText.includes('RF???') && hasAny(combined, ['???'])) return 'RF SAR ?????';
  if (departmentText.includes('RF????')) {
    if (hasAny(combined, ['?????', '????'])) return 'WE1????(????)';
    if (hasAny(combined, ['???', '??'])) return 'WE1??????';
  }
  if (department === '??' && hasAny(combined, ['EMC', '?????', '???'])) return '???????';
  if (department === '??') {
    if (hasAny(combined, ['ICC?????'])) return 'ICC ?????';
    if (hasAny(combined, ['ICCPM'])) return 'ICC PM';
    if (hasAny(combined, ['????'])) return 'ICC ????';
  }
  if (department === '??') {
    if (hasAny(combined, ['????'])) return '??????';
    if (hasAny(combined, ['????'])) return '??????';
    if (hasAny(combined, ['RFPM'])) return '??RF PM';
    if (hasAny(combined, ['WE1????'])) return 'WE1????(????)';
    if (hasAny(combined, ['WE1', '?????'])) return 'WE1??????';
    if (hasAny(combined, ['SAR??'])) return 'SAR????';
  }
  if (department === '??/??') {
    if (hasAny(combined, ['MIS'])) return 'MIS???';
    if (hasAny(combined, ['??????'])) return '??????';
    if (hasAny(combined, ['???'])) return '?????/??';
    if (hasAny(combined, ['?????'])) return '?????';
    if (hasAny(combined, ['?????'])) return '?????';
  }
  if (department === '??' && hasAny(combined, ['??'])) return '???????';
  return String(rawPosition || '').trim() || null;
};
const rawDepartment = aiResult.department || null;
const rawPosition = aiResult.position || null;
const canonicalDepartment = canonicalizeDepartment(rawDepartment, base.email_subject);
const canonicalPosition = canonicalizePosition(rawPosition, canonicalDepartment, rawDepartment, base.email_subject);

return {
  email_msg_id: base.email_msg_id,
  email_subject: base.email_subject,
  email_web_link: base.email_web_link,
  sender: base.sender,
  received_at: base.received_at,
  source_type: 'onboarding',
  name: base.name_from_subject || aiResult.name || '未知姓名',
  scheduled_onboard_date: regexDate || aiResult.scheduled_onboard_date || null,
  raw_department: rawDepartment,
  raw_position: rawPosition,
  department: canonicalDepartment || rawDepartment,
  position: canonicalPosition || rawPosition,
  hr_owner: aiResult.hr_owner || null,
  intent: aiResult.intent || 'new_onboard',
};
